public final T handle(ResultSet rs) throws SQLException {
    if (this.rs != null) {
        throw new IllegalStateException("Re-entry not allowed!");
    }

    this.rs = rs;

    try {
        return handle();
    } finally {
        this.rs = null;
    }
}

