protected PreparedStatement prepareStatement(Connection conn, String sql)
        throws SQLException {

    PreparedStatement ps = conn.prepareStatement(sql);
    try {
        configureStatement(ps);
    } catch (SQLException e) {
        ps.close();
        throw e;
    }
    return ps;
}

