original_method:
public static void printStackTrace(SQLException e, PrintWriter pw) {

    SQLException next = e;
    while (next != null) {
        next.printStackTrace(pw);
        next = next.getNextException();
        if (next != null) {
            pw.println("Next SQLException:");
        }
    }
}

