    if ("java.sql.Timestamp".equals(targetType)) {
        Timestamp tsValue = (Timestamp) value;
        int nanos = tsValue.getNanos();
        value = new java.sql.Timestamp(tsValue.getTime());
        ((Timestamp) value).setNanos(nanos);
    }

    return value;
}

